import{_ as o}from"./chunks/macro_cc.DXrgawS2.js";import{_ as r,C as n,o as s,c as i,a3 as l,E as d,w as u,j as t}from"./chunks/framework.CCylkYel.js";const M=JSON.parse('{"title":"Control Change","description":"","frontmatter":{"title":"Control Change","pageClass":"macro-doc"},"headers":[],"relativePath":"macros/control-change.md","filePath":"macros/control-change.md"}'),c={name:"macros/control-change.md"};function m(h,e,g,p,C,b){const a=n("ManualRelated");return s(),i("div",null,[e[1]||(e[1]=l('<h1 id="control-change" tabindex="-1">Control Change <a class="header-anchor" href="#control-change" aria-label="Permalink to &quot;Control Change&quot;">​</a></h1><p><strong>Firmware menu name:</strong> CC</p><p>Send 7-bit MIDI Control Change messages.</p><p><img src="'+o+'" alt="Control Change macro" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Use <strong>CC</strong> for the most common MIDI knob → synth parameter mapping. Pick the controller number (MSB), set min/max to the CC range you need, and choose outputs.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Mode</td><td>—</td><td>Macro output type. Change this to switch between MIDI, internal routing, and CV16 targets.</td></tr><tr><td>MSB</td><td>0 – 127</td><td>Most significant byte. For <strong>CC</strong> and <strong>CC14</strong> this is the control number; for <strong>NRPN</strong> / <strong>RPN</strong> it is the parameter number MSB.</td></tr><tr><td>Minimum</td><td>Mode-specific</td><td>Value sent when the knob is at minimum travel. Units follow the target (MIDI 0–127, 14-bit 0–16383, device parameter native range, CV volts, LFO %, etc.).</td></tr><tr><td>Maximum</td><td>Mode-specific</td><td>Value sent when the knob is at maximum travel. Must be greater than or equal to <strong>Minimum</strong>.</td></tr><tr><td>Channel</td><td>Global, 1 – 16</td><td>MIDI channel for outgoing messages. <strong>Global</strong> uses the project&#39;s global channel setting.</td></tr><tr><td>Invert</td><td>True / False</td><td>When <strong>True</strong>, knob clockwise motion maps to decreasing values (minimum ↔ maximum swapped).</td></tr><tr><td>Outputs</td><td>USB / DIN / combos</td><td>Which physical MIDI outputs carry this macro: USB, <strong>Out 1</strong>, <strong>Out 2</strong>, or combined masks.</td></tr></tbody></table></div><h2 id="midi-outputs" tabindex="-1">MIDI outputs <a class="header-anchor" href="#midi-outputs" aria-label="Permalink to &quot;MIDI outputs&quot;">​</a></h2><p>The <strong>Outputs</strong> field selects one of these port combinations:</p><ul><li>None</li><li>USB</li><li>Out 1</li><li>USB + Out 1</li><li>Out 2</li><li>USB + Out 2</li><li>Out 1 + Out 2</li><li>USB + Out 1 + Out 2</li></ul>',11)),d(a,{title:"Related topics"},{default:u(()=>[...e[0]||(e[0]=[t("ul",null,[t("li",null,[t("a",{href:"/macros/"},"Macros overview")]),t("li",null,[t("a",{href:"/macros/setting-up-macros"},"Setting up macros")]),t("li",null,[t("a",{href:"/concepts/modulation"},"Modulation")])],-1)])]),_:1})])}const I=r(c,[["render",m]]);export{M as __pageData,I as default};
